#include <vector>
#include <iostream>
using namespace std;

class Solution { public: vector<int> solve(Node* root) {
    vector<int> res;
    dfs(root, res);
    return res;

    void dfs(Node* node, vector<int>& res) {
        if (node) {
            dfs(node->left, res);
            res.push_back(node->val);
            dfs(node->right, res);
        }
    }
};
